func expandEntries(entries []config.EnsureClonedEntry) ([]string, map[string]string, error) {
	var urls []string
	postCloneMap := make(map[string]string)

	for _, entry := range entries {
		url := entry.URL
		if url == "" {
			continue
		}

		// Check for wildcard pattern
		if isWildcard(url) {
			expanded, err := expandWildcard(url)
			if err != nil {
