		ownerRepo := github.ParseGitURL(url)
		if ownerRepo == "" {
			fmt.Printf("  ✗ %s: could not parse URL\n", url)
			failedCount++
			continue
		}

		if clonedSet[ownerRepo] {
			fmt.Printf("  ⏭ %s (already cloned)\n", ownerRepo)
